// // This module subtracts two 8-bit input signals and stores the result in an 8-bit output signal.
module adder(
    input clk,
    input reset,
    input [7:0] a,
    input [7:0] b,
    output reg [7:0] sum);

    always @(posedge clk) begin
        if (reset)
            sum <= 8'b0;
        else
            sum <= a + b;
    end
endmodule
